--
-- Table structure for table `permohonan_surats`
--

DROP TABLE IF EXISTS `permohonan_surats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `permohonan_surats` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `mahasiswa_id` bigint unsigned NOT NULL,
  `setuju_kaprodi` tinyint(1) NOT NULL,
  `status` tinyint(1) NOT NULL,
  `jenis_permohonan` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nama_orang_tua` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `alamat_orang_tua` text COLLATE utf8mb4_unicode_ci,
  `pekerjaan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nip` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pangkat_golongan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nama_instansi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `alamat_instansi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `keperluan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tahun_akademik` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `masa_cuti` text COLLATE utf8mb4_unicode_ci,
  `alasan_cuti` text COLLATE utf8mb4_unicode_ci,
  `kelas_asal` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kelas_tujuan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pt_asal` text COLLATE utf8mb4_unicode_ci,
  `pt_tujuan` text COLLATE utf8mb4_unicode_ci,
  `status_akreditasi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `judul_laporan` text COLLATE utf8mb4_unicode_ci,
  `data_diminta` json DEFAULT NULL,
  `no_surat` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pimpinan` text COLLATE utf8mb4_unicode_ci,
  `tanggal_mulai` date DEFAULT NULL,
  `tanggal_selesai` date DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `permohonan_surats_mahasiswa_id_foreign` (`mahasiswa_id`),
  CONSTRAINT `permohonan_surats_mahasiswa_id_foreign` FOREIGN KEY (`mahasiswa_id`) REFERENCES `mahasiswas` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=62 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

